import sys
from typing import List

class Solution:
    def findTargetSumWays(self, nums: List[int], target: int) -> int:
        dp = {}
        dp[0] = 1
        for num in nums:
            temp = {}
            for sum_val, count in dp.items():
                temp[sum_val + num] = temp.get(sum_val + num, 0) + count
                temp[sum_val - num] = temp.get(sum_val - num, 0) + count
            dp = temp
        return dp.get(target, 0)

