#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int findTargetSumWays(vector<int>& nums, int target) {
        unordered_map<int, int> dp;
        dp[0] = 1;
        for (int num : nums) {
            unordered_map<int, int> temp;
            for (auto& pair : dp) {
                temp[pair.first + num] += pair.second;
                temp[pair.first - num] += pair.second;
            }
            dp = temp;
        }
        return dp[target];
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> nums(n);
    for (int i = 0; i < n; i++) cin >> nums[i];
    int target;
    if (!(cin >> target)) return 0;
    Solution sol;
    int ans = sol.findTargetSumWays(nums, target);
    cout << ans << "\n";
    return 0;
}
